index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif; color: #333; line-height: 1.8; background: #feffff; }
    .hero { background: #333; color: #feffff; padding: 100px 20px; text-align: center; position: relative; overflow: hidden; }
    .hero::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(21,183,136,0.2) 0%, transparent 55%, rgba(255,152,0,0.08) 100%); }
    .hero-inner { position: relative; max-width: 720px; margin: 0 auto; }
    .hero .eyebrow { display: inline-block; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); border-radius: 100px; padding: 6px 18px; font-size: 0.8rem; margin-bottom: 1.5rem; color: #15b788; }
    .hero h1 { font-size: 2.6rem; font-weight: 800; margin-bottom: 0.3rem; }
    .hero h1 small { font-size: 1.15rem; font-weight: 400; display: block; color: #15b788; margin-top: 0.3rem; }
    .hero .desc { font-size: 1rem; opacity: 0.9; max-width: 580px; margin: 1.5rem auto 0; }
    .compare-hero { display: flex; justify-content: center; gap: 16px; margin-top: 2.5rem; flex-wrap: wrap; align-items: stretch; }
    .compare-box { flex: 1; min-width: 140px; max-width: 220px; border-radius: 14px; padding: 20px 16px; text-align: center; }
    .compare-box.before { background: rgba(255,255,255,0.06); border: 1px dashed rgba(255,255,255,0.25); opacity: 0.85; }
    .compare-box.after { background: rgba(21,183,136,0.22); border: 2px solid #15b788; }
    .compare-box .label { font-size: 0.7rem; letter-spacing: 0.08em; opacity: 0.7; margin-bottom: 8px; }
    .compare-box .emoji { font-size: 2rem; margin-bottom: 6px; }
    .compare-box .text { font-size: 0.9rem; font-weight: 600; line-height: 1.5; }
    .compare-arrow { display: flex; align-items: center; font-size: 1.5rem; color: #15b788; font-weight: 700; }
    section { padding: 80px 20px; }
    section:nth-child(even) { background: #f8f9fa; }
    .container { max-width: 800px; margin: 0 auto; }
    .section-title { font-size: 1.6rem; font-weight: 700; text-align: center; margin-bottom: 0.5rem; }
    .section-subtitle { text-align: center; color: #888; font-size: 0.95rem; margin-bottom: 3rem; }
    .pain-list { display: grid; gap: 16px; margin-bottom: 2rem; }
    .pain-item { background: #fff; border-radius: 12px; padding: 20px 24px; border-left: 4px solid #ccc; box-shadow: 0 1px 4px rgba(0,0,0,0.04); }
    .pain-item strong { display: block; color: #555; margin-bottom: 4px; font-size: 0.95rem; }
    .pain-item span { font-size: 0.9rem; color: #777; }
    .solution-banner { background: linear-gradient(135deg, #eefaf5 0%, #fff8ee 100%); border-radius: 16px; padding: 28px 32px; text-align: center; border: 1px solid rgba(21,183,136,0.25); margin-bottom: 2rem; }
    .solution-banner p { font-size: 1.05rem; color: #333; font-weight: 600; }
    .solution-banner .highlight { color: #15b788; }
    .flow { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 12px; align-items: center; margin: 2rem 0; }
    .flow-step { background: #fff; border-radius: 12px; padding: 20px; text-align: center; border: 1px solid #eee; }
    .flow-step .icon { font-size: 1.8rem; margin-bottom: 8px; }
    .flow-step h3 { font-size: 0.95rem; margin-bottom: 4px; }
    .flow-step p { font-size: 0.8rem; color: #666; }
    .flow-arrow { text-align: center; color: #15b788; font-size: 1.2rem; font-weight: 700; }
    .features-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; }
    .feature-card { background: #fff; border-radius: 12px; padding: 28px; border: 1px solid #eee; }
    .feature-card .icon { font-size: 2rem; margin-bottom: 0.8rem; }
    .feature-card h3 { font-size: 1rem; margin-bottom: 0.5rem; }
    .feature-card p { font-size: 0.85rem; color: #666; line-height: 1.6; }
    .insight-card { background: #fff; border-radius: 16px; padding: 28px 32px; border: 1px solid #eee; margin-bottom: 16px; }
    .insight-card h3 { font-size: 1.05rem; color: #15b788; margin-bottom: 0.6rem; }
    .insight-card p { font-size: 0.95rem; color: #555; }
    .cta-section { text-align: center; }
    .cta-section .btn { display: inline-block; background: #15b788; color: #fff; text-decoration: none; padding: 14px 32px; border-radius: 10px; font-weight: 700; margin: 6px; }
    .cta-section .btn.secondary { background: #1395ba; }
    .cta-section .micro { margin-top: 1rem; font-size: 0.8rem; color: #999; }
    footer { text-align: center; padding: 32px 20px; border-top: 1px solid #eee; font-size: 0.85rem; color: #888; }
    footer a { color: #1395ba; text-decoration: none; }
    footer .links a { margin: 0 12px; }
    @media (max-width: 640px) {
      .hero h1 { font-size: 2rem; }
      .compare-arrow { width: 100%; justify-content: center; transform: rotate(90deg); margin: -8px 0; }
      .flow-arrow { transform: rotate(90deg); }
    }
    .screenshot-gallery {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 20px;
      margin-top: 2rem;
    }
    .screenshot-item {
      border-radius: 12px;
      overflow: hidden;
      box-shadow: 0 2px 12px rgba(0,0,0,0.08);
      transition: transform 0.2s, box-shadow 0.2s;
      background: #fff;
    }
    .screenshot-item:hover {
      transform: translateY(-3px);
      box-shadow: 0 6px 24px rgba(0,0,0,0.12);
    }
    .screenshot-item img { width: 100%; height: auto; display: block; }
    .screenshot-label {
      display: block;
      padding: 12px 16px;
      font-size: 0.85rem;
      color: #555;
      text-align: center;
      font-weight: 600;
    }

